pub fn buy(ctx: Context<Buy>, sol_amount_in: u64, minimum_tokens_out: u64) -> Result<()> {
    require!(sol_amount_in > 0, LaunchpadError::ZeroAmount);
    require!(ctx.accounts.curve.status == STATUS_TRADING, LaunchpadError::TradingClosed);

    let remaining_to_threshold = ctx
        .accounts
        .curve
        .migration_threshold_lamports
        .checked_sub(ctx.accounts.curve.real_sol_reserves)
        .ok_or(LaunchpadError::MathOverflow)?;
    require!(remaining_to_threshold > 0, LaunchpadError::TradingClosed);

    // Treat sol_amount_in as the buyer's maximum spend. If this buy would
    // cross graduation, only collect the exact gross amount needed to land
    // on the threshold. The unused SOL never leaves the buyer's wallet.
    let quoted_fee = calculate_fee(sol_amount_in, ctx.accounts.curve.fee_bps)?;
    let quoted_net = sol_amount_in
        .checked_sub(quoted_fee)
        .ok_or(LaunchpadError::MathOverflow)?;
    let (gross_sol_accepted, fee, net_sol) = if quoted_net > remaining_to_threshold {
        let gross = gross_from_net(remaining_to_threshold, ctx.accounts.curve.fee_bps)?;
        require!(gross <= sol_amount_in, LaunchpadError::MathOverflow);
        let capped_fee = gross
            .checked_sub(remaining_to_threshold)
            .ok_or(LaunchpadError::MathOverflow)?;
        (gross, capped_fee, remaining_to_threshold)
    } else {
        (sol_amount_in, quoted_fee, quoted_net)
    };
    require!(net_sol > 0, LaunchpadError::ZeroAmount);

    let tokens_out = quote_buy(
        ctx.accounts.curve.virtual_sol_reserves,
        ctx.accounts.curve.virtual_token_reserves,
        net_sol,
    )?;
    require!(tokens_out >= minimum_tokens_out, LaunchpadError::SlippageExceeded);
    require!(tokens_out > 0, LaunchpadError::ZeroOutput);
    require!(
        tokens_out <= ctx.accounts.curve.real_token_reserves,
        LaunchpadError::InsufficientCurveTokens
    );

    let transfer_net = anchor_lang::system_program::Transfer {
        from: ctx.accounts.buyer.to_account_info(),
        to: ctx.accounts.curve.to_account_info(),
    };
    anchor_lang::system_program::transfer(
        CpiContext::new(ctx.accounts.system_program.to_account_info(), transfer_net),
        net_sol,
    )?;

    if fee > 0 {
        let transfer_fee = anchor_lang::system_program::Transfer {
            from: ctx.accounts.buyer.to_account_info(),
            to: ctx.accounts.fee_receiver.to_account_info(),
        };
        anchor_lang::system_program::transfer(
            CpiContext::new(ctx.accounts.system_program.to_account_info(), transfer_fee),
            fee,
        )?;
    }

    let mint_key = ctx.accounts.mint.key();
    let curve_bump = ctx.accounts.curve.bump;
    let signer_seeds: &[&[&[u8]]] = &[&[b"curve", mint_key.as_ref(), &[curve_bump]]];
    token::transfer(
        CpiContext::new_with_signer(
            ctx.accounts.token_program.to_account_info(),
            Transfer {
                from: ctx.accounts.token_vault.to_account_info(),
                to: ctx.accounts.buyer_token_account.to_account_info(),
                authority: ctx.accounts.curve.to_account_info(),

          },
            signer_seeds,
        ),
        tokens_out,
    )?;

    let curve = &mut ctx.accounts.curve;
    curve.virtual_sol_reserves = curve
        .virtual_sol_reserves
        .checked_add(net_sol)
        .ok_or(LaunchpadError::MathOverflow)?;
    curve.virtual_token_reserves = curve
        .virtual_token_reserves
        .checked_sub(tokens_out)
        .ok_or(LaunchpadError::MathOverflow)?;
    curve.real_sol_reserves = curve
        .real_sol_reserves
        .checked_add(net_sol)
        .ok_or(LaunchpadError::MathOverflow)?;
    curve.real_token_reserves = curve
        .real_token_reserves
        .checked_sub(tokens_out)
        .ok_or(LaunchpadError::MathOverflow)?;

    if curve.real_sol_reserves >= curve.migration_threshold_lamports {
        curve.status = STATUS_MIGRATION_READY;
        emit!(MigrationReady {
            curve: curve.key(),
            mint: curve.mint,
            sol_raised: curve.real_sol_reserves,
        });
    }

    emit!(Trade {
        curve: curve.key(),
        user: ctx.accounts.buyer.key(),
        is_buy: true,
        sol_amount: gross_sol_accepted,
        token_amount: tokens_out,
        fee_amount: fee,
    });
    Ok(())
}

